INSERT INTO quiz_questions (quiz_id, question_text, question_type, options, correct_answer, explanation)
VALUES
('bd8db023-eae7-42c2-82ca-85209577ee9c', 'Bối cảnh phổ biến nhất của Section 3 IELTS Listening là gì?', 'multiple_choice', '["Một người hướng dẫn viên đang thuyết minh trên xe buýt.","Một cuộc hội thoại từ 2 đến tối đa 4 người trong bối cảnh giáo dục, học thuật (ví dụ: sinh viên thảo luận nhóm về dự án, sinh viên gặp giáo sư hướng dẫn).","Một đoạn quảng cáo trên radio.","Người gọi điện mua vé máy bay."]', 'Một cuộc hội thoại từ 2 đến tối đa 4 người trong bối cảnh giáo dục, học thuật (ví dụ: sinh viên thảo luận nhóm về dự án, sinh viên gặp giáo sư hướng dẫn).', 'Section 3 là bước chuyển giao sang ngôn ngữ học thuật (Academic context). Khó khăn lớn nhất là phải phân biệt được giọng nói và quan điểm của nhiều người khác nhau.'),
('bd8db023-eae7-42c2-82ca-85209577ee9c', 'Dạng câu hỏi Trắc nghiệm nhiều lựa chọn (Multiple Choice) ở Section 3 thường chứa bẫy gì phổ biến nhất?', 'multiple_choice', '["Các đáp án sai được đọc bằng ngôn ngữ khác.","Tất cả các phương án A, B, C đều được người nói nhắc đến trong đoạn băng, nhưng chỉ có một phương án thực sự trả lời đúng trọng tâm câu hỏi hoặc được các bên ''chốt'' lại cuối cùng.","Chỉ có đáp án đúng mới được nhắc đến.","Không có từ vựng nào trong đáp án giống với đoạn băng."]', 'Tất cả các phương án A, B, C đều được người nói nhắc đến trong đoạn băng, nhưng chỉ có một phương án thực sự trả lời đúng trọng tâm câu hỏi hoặc được các bên ''chốt'' lại cuối cùng.', 'Bẫy Mention (Nhắc đến) rất nguy hiểm. A có thể đề xuất phương án X, nhưng B bác bỏ, và cuối cùng họ chọn Y. Việc nghe bắt chữ khóa (word matching) sẽ khiến bạn mất điểm lập tức.'),
('bd8db023-eae7-42c2-82ca-85209577ee9c', 'Kỹ năng cực kỳ quan trọng để xử lý Section 3 là nhận diện ''Sự đồng thuận'' (Agreement). Cụm từ nào sau đây mang ý nghĩa bác bỏ ý kiến?', 'multiple_choice', '["I couldn''t agree more.","That''s exactly how I feel.","I see your point, but...","That makes sense."]', 'I see your point, but...', 'Trong thảo luận nhóm, một người thường đưa ra ý kiến, và người kia sẽ đồng tình hoặc phản bác (phản bác lịch sự bằng ''but''). Đáp án cuối cùng phụ thuộc vào việc họ có đạt được sự đồng thuận hay không.'),
('f47f3aa3-4971-4b71-9501-998b2fecdf5e', 'Đặc trưng lớn nhất làm nên độ khó của Section 4 IELTS Listening là gì?', 'multiple_choice', '["Giọng đọc luôn là tiếng Anh Úc.","Đây là một bài giảng học thuật (Academic Lecture) độc thoại và KHÔNG có khoảng thời gian nghỉ (No break) ở giữa để thí sinh đọc trước câu hỏi.","Thí sinh phải tự viết ra câu trả lời dài 10 từ.","Băng sẽ chạy nhanh gấp đôi."]', 'Đây là một bài giảng học thuật (Academic Lecture) độc thoại và KHÔNG có khoảng thời gian nghỉ (No break) ở giữa để thí sinh đọc trước câu hỏi.', 'Ở các section trước, băng sẽ dừng ở giữa (ví dụ: ''You have some time to look at questions 1 to 5''). Ở Section 4, bạn phải tập trung liên tục cho trọn vẹn 10 câu hỏi từ 31 đến 40.'),
('f47f3aa3-4971-4b71-9501-998b2fecdf5e', 'Dạng bài gần như độc tôn xuất hiện trong Section 4 Listening là gì?', 'multiple_choice', '["Nối hình ảnh con vật.","Note Completion (Hoàn thành bản tóm tắt bài giảng bằng cách điền 1-2 từ).","Multiple choice 5 lựa chọn.","Map Labeling."]', 'Note Completion (Hoàn thành bản tóm tắt bài giảng bằng cách điền 1-2 từ).', 'Bài thi đánh giá khả năng nghe hiểu và ghi chú (note-taking) của sinh viên trong một giảng đường đại học.'),
('f47f3aa3-4971-4b71-9501-998b2fecdf5e', 'Để không bị ''lạc trôi'' trong suốt 5 phút của Section 4, bạn bắt buộc phải bám sát vào thứ gì?', 'multiple_choice', '["Các số liệu toán học.","Ngữ pháp của các câu.","Các ''Signposting words'' (Từ dẫn đường) như: Firstly, Turning to the next point, Lastly... và các đề mục (Headings) in đậm trong tờ đề thi.","Tiếng ho của giáo sư."]', 'Các ''Signposting words'' (Từ dẫn đường) như: Firstly, Turning to the next point, Lastly... và các đề mục (Headings) in đậm trong tờ đề thi.', 'Bài giảng được chia thành các phần rõ ràng. Việc theo dõi các cụm từ chuyển ý giúp mắt bạn di chuyển xuống đúng câu hỏi tiếp theo cùng lúc với diễn giả.'),
('11de56b9-fa22-4bca-9c6e-ebb7a5575728', 'Trong khoảng thời gian 30 giây được cho trước khi đoạn băng chạy, chiến lược ''Đoán trước'' (Predicting) yêu cầu bạn làm gì?', 'multiple_choice', '["Đoán xem giọng đọc là Anh hay Mỹ.","Đọc lướt câu hỏi, phân tích ngữ pháp để dự đoán xem chỗ trống cần điền là Danh từ, Động từ, Tính từ hay Con số, Tên riêng.","Nhắm mắt lại và nhẩm lại từ vựng.","Viết sẵn đáp án lụi vào giấy."]', 'Đọc lướt câu hỏi, phân tích ngữ pháp để dự đoán xem chỗ trống cần điền là Danh từ, Động từ, Tính từ hay Con số, Tên riêng.', 'Ví dụ: ''cost: £____'' (Chắc chắn là số). ''needs to buy a ____'' (Chắc chắn là danh từ số ít). Việc dự đoán giúp não bộ lập trình sẵn để ''đón'' đúng loại thông tin.'),
('11de56b9-fa22-4bca-9c6e-ebb7a5575728', 'Việc đọc phần Tiêu đề (Title) của bài Listening trước khi nghe mang lại lợi ích lớn nhất nào?', 'multiple_choice', '["Giúp tính toán số lượng chữ cần viết.","Kích hoạt ''Schema'' (Kiến thức nền) trong não bộ, giúp bạn lôi ra các từ vựng liên quan đến chủ đề đó và sẵn sàng đón nhận bối cảnh câu chuyện.","Không có lợi ích gì đáng kể.","Giúp biết trước đáp án."]', 'Kích hoạt ''Schema'' (Kiến thức nền) trong não bộ, giúp bạn lôi ra các từ vựng liên quan đến chủ đề đó và sẵn sàng đón nhận bối cảnh câu chuyện.', 'Nếu tiêu đề là ''Whale Conservation'' (Bảo tồn cá voi), bạn sẽ chuẩn bị tâm lý nghe về biển, sự tuyệt chủng, săn bắt... Việc này tăng 50% khả năng nghe hiểu.'),
('11de56b9-fa22-4bca-9c6e-ebb7a5575728', 'Nếu bạn bị lỡ mất một câu trả lời (Missed an answer) trong lúc băng đang chạy, phản xạ kỷ luật nhất là gì?', 'multiple_choice', '["Dừng lại suy nghĩ cố nhớ xem họ vừa nói gì.","Chấp nhận bỏ qua ngay lập tức, nhanh chóng di chuyển mắt xuống câu tiếp theo để không bị lỡ hiệu ứng dây chuyền (Domino effect).","Bật khóc và bỏ thi.","Tháo tai nghe ra."]', 'Chấp nhận bỏ qua ngay lập tức, nhanh chóng di chuyển mắt xuống câu tiếp theo để không bị lỡ hiệu ứng dây chuyền (Domino effect).', 'Băng chỉ chạy 1 lần duy nhất. Tiếc nuối 1 câu sẽ khiến bạn mất tiếp 3 câu sau đó vì không còn biết người nói đang ở đoạn nào.'),
('5197af9e-b529-47d7-9c21-a78774fcb12a', 'Trong phần thi Đánh vần tên (Spelling), hai chữ cái nào thí sinh Việt Nam thường xuyên nghe nhầm lẫn nhất?', 'multiple_choice', '["A và O","G và J, E và I","B và P","S và X"]', 'G và J, E và I', 'Chữ ''G'' (/dʒiː/) và ''J'' (/dʒeɪ/); chữ ''E'' (/i:/) và ''I'' (/aɪ/) là những cái bẫy kinh điển cướp điểm của thí sinh do phát âm tiếng Việt khác biệt.'),
('5197af9e-b529-47d7-9c21-a78774fcb12a', 'Khi nghe phân biệt các số đuôi ''-teen'' (như 13, 14) và đuôi ''-ty'' (như 30, 40), đặc điểm phát âm nào giúp bạn nhận ra số đúng?', 'multiple_choice', '["Số có đuôi -teen được đọc ngắn hơn.","Trong đuôi ''-teen'', trọng âm nhấn mạnh và kéo dài ở âm tiết thứ hai (thir-TEEN); trong đuôi ''-ty'', trọng âm nhấn ở âm tiết đầu và đuôi đọc lướt (THIR-ty).","Hai số này được phát âm y hệt nhau, phải đoán theo ngữ cảnh.","Đuôi ''-ty'' có âm /s/ ở cuối."]', 'Trong đuôi ''-teen'', trọng âm nhấn mạnh và kéo dài ở âm tiết thứ hai (thir-TEEN); trong đuôi ''-ty'', trọng âm nhấn ở âm tiết đầu và đuôi đọc lướt (THIR-ty).', 'Trọng âm là chìa khóa duy nhất. Người bản xứ thường đọc lướt chữ ''t'' trong số 30 thành âm /d/ (thir-dy), nhưng với 13 thì chữ ''TEEN'' luôn được kéo dài rõ ràng.'),
('5197af9e-b529-47d7-9c21-a78774fcb12a', 'Định dạng ngày tháng trong tiếng Anh có thể được người nói đọc bằng nhiều cách. Nếu đáp án cần điền giới hạn 1 từ và/hoặc 1 số, bạn nghe thấy ''the 15th of November'', bạn sẽ viết thế nào vào bài thi?', 'multiple_choice', '["fifteenth of November","15th of November","15 November","November the 15th"]', '15 November', '''15 November'' được tính là 1 số (15) và 1 từ (November), hoàn toàn hợp lệ và tránh được lỗi sai chính tả chữ ''th''.'),
('930a1850-99b5-429e-a23f-a352bb5c1ff3', 'Kỹ năng ''Paraphrasing'' trong bài thi Listening có nghĩa là gì?', 'multiple_choice', '["Băng ghi âm sẽ đọc chính xác từng chữ được in trên đề thi.","Nội dung băng ghi âm sẽ diễn đạt lại ý của câu hỏi bằng các từ đồng nghĩa (Synonyms) hoặc cấu trúc ngữ pháp khác, buộc thí sinh phải nghe hiểu ý thay vì bắt chữ khóa.","Người nói sẽ đọc một ngôn ngữ khác.","Người nói sẽ phát âm sai từ cố ý."]', 'Nội dung băng ghi âm sẽ diễn đạt lại ý của câu hỏi bằng các từ đồng nghĩa (Synonyms) hoặc cấu trúc ngữ pháp khác, buộc thí sinh phải nghe hiểu ý thay vì bắt chữ khóa.', 'Đây là cốt lõi của IELTS Listening. Nếu đề ghi ''cheap'', băng có thể nói ''cost-effective'' hoặc ''inexpensive''.'),
('930a1850-99b5-429e-a23f-a352bb5c1ff3', 'Nếu câu hỏi trong đề ghi ''Lack of space'', bạn nên chuẩn bị tâm lý để nghe cụm từ nào đồng nghĩa trong đoạn băng?', 'multiple_choice', '["A lot of room.","Not enough room / Insufficient space.","Space exploration.","Empty space."]', 'Not enough room / Insufficient space.', '''Lack of'' thường được paraphrase thành ''not enough'', ''insufficient'', hoặc ''shortage of''. Việc dự đoán trước các synonyms này giúp não bộ phản xạ tức thì khi âm thanh phát lên.'),
('930a1850-99b5-429e-a23f-a352bb5c1ff3', 'Sự thay đổi ''Word class'' (Từ loại) là một hình thức paraphrase cực kỳ phổ biến. Nếu đề bài sử dụng Danh từ ''A reduction in price'', đoạn băng có thể dùng Động từ nào?', 'multiple_choice', '["The price is increased.","They reduced the price / Prices were lowered.","It is very cheap.","Price reduction is good."]', 'They reduced the price / Prices were lowered.', 'Tác giả chuyển đổi linh hoạt giữa Danh từ (reduction) và Động từ (reduce/lower) để ẩn giấu đáp án.'),
('63308e54-8533-41af-b10e-08350cc6152c', 'Sau khi kết thúc trọn vẹn 4 Section (khoảng 30 phút) trong bài thi IELTS Listening trên GIẤY (Paper-based), thí sinh sẽ có thêm bao nhiêu thời gian để làm gì?', 'multiple_choice', '["Có 5 phút để đi vệ sinh.","Có 10 phút để chuyển (transfer) đáp án từ đề thi sang tờ Answer Sheet chính thức.","Không có thời gian, phải nộp bài ngay.","Có 2 phút để kiểm tra lại với bạn bên cạnh."]', 'Có 10 phút để chuyển (transfer) đáp án từ đề thi sang tờ Answer Sheet chính thức.', 'Trong lúc nghe, bạn nên viết nháp thật nhanh lên đề thi. 10 phút cuối cùng này là lúc để nắn nót viết vào Answer Sheet và kiểm tra cẩn thận chính tả.'),
('63308e54-8533-41af-b10e-08350cc6152c', 'Khi chuyển đáp án (transfer answers), lỗi nào sau đây dẫn đến việc bạn bị mất điểm oan uổng nhất?', 'multiple_choice', '["Viết hoa toàn bộ các chữ cái (ALL CAPS).","Ghi nhầm vị trí số thứ tự câu hỏi (ví dụ: đáp án câu 15 lại ghi vào ô 16), dẫn đến sai hàng loạt.","Sử dụng bút chì thay vì bút bi.","Chữ viết quá đẹp."]', 'Ghi nhầm vị trí số thứ tự câu hỏi (ví dụ: đáp án câu 15 lại ghi vào ô 16), dẫn đến sai hàng loạt.', 'Lỗi lệch dòng (Misalignment) là cơn ác mộng. Bạn nên luôn dùng ngón tay chỉ vào số thứ tự trên đề và trên Answer sheet để đối chiếu.'),
('63308e54-8533-41af-b10e-08350cc6152c', 'Quy định về việc Viết hoa (Capitalization) trong tờ Answer Sheet của IELTS Listening là gì?', 'multiple_choice', '["Bắt buộc phải viết hoa chữ cái đầu tiên của mọi từ.","Tuyệt đối không được viết hoa.","Chỉ viết hoa tên người.","Có thể viết hoa toàn bộ tất cả các chữ cái (ALL CAPS) để đảm bảo độ rõ ràng và giám khảo dễ đọc nhất."]', 'Có thể viết hoa toàn bộ tất cả các chữ cái (ALL CAPS) để đảm bảo độ rõ ràng và giám khảo dễ đọc nhất.', 'Hội đồng thi khuyến khích thí sinh viết ALL CAPS (ví dụ: COMPUTER thay vì computer) để tránh việc chữ viết tay quá xấu khiến giám khảo không dịch được hoặc sai quy tắc viết hoa tên riêng.');